const tr=(k,vars={})=>{let v=(I18N[language]||I18N.fr)[k]||k;for(const [a,b] of Object.entries(vars))v=v.replaceAll(`{${a}}`,b);return v};
const locale=()=>language==='en'?'en-GB':'fr-FR';
const fmt=d=>d?new Intl.DateTimeFormat(locale()).format(new Date(d+'T12:00:00')):'—';
const planningText=i=>i.start_time?`${i.start_time}${i.end_time?'–'+i.end_time:''}`:tr('missingTime');
function setText(id,key){const e=$(id);if(e)e.textContent=tr(key)}
function applyLanguage(){
 document.documentElement.lang=language;$('languageSwitch').value=language;
 setText('languageLabel','language');$('themeText').textContent=document.documentElement.dataset.theme==='light'?tr('dark'):tr('light');
 const keys=['dashboard','today','history'];document.querySelectorAll('.nav[data-view]').forEach((n,i)=>{if(keys[i])n.textContent=tr(keys[i])});setText('settingsNav','settings');setText('profileNav','profileNav');setText('reportsNav','reports');setText('logoutNav','logout');const tabKeys={general:'settingsGeneral',communications:'settingsCommunications',smtp:'settingsSmtp',redmine:'settingsRedmine',users:'settingsUsers',ldap:'settingsLdap',sso:'settingsSso',logs:'settingsLogs',health:'settingsHealth',backups:'settingsBackups',system:'settingsSystem'};document.querySelectorAll('.settings-tab').forEach(b=>{const icon=(b.textContent.match(/^[^A-Za-zÀ-ÿ]+/)||[''])[0];b.textContent=icon+tr(tabKeys[b.dataset.settingsTab]||b.dataset.settingsTab)});setText('refresh','syncNow');setText('dialogCloseBottom','close');setText('pdfLink','viewPdf');setText('d-link','openTicket');
 const ids={filterEnvLabel:'environment',filterStatusLabel:'status',filterPriorityLabel:'priority',filterTimeLabel:'schedule',todayBtn:'todayStat',calendarHelp:'calendarHelp',dialogDescriptionTitle:'description',dialogCommunicationTitle:'communication',resendRecipientsLabel:'resendAddresses',resendNoteLabel:'optionalNote',includePdfLabel:'attachPdf',resendDefaultTitle:'resendConfigured',resendDefaultHint:'configuredHint',resendCustom:'resendEntered',settingsEyebrow:'customization',settingsTitle:'companyIdentity',companyNameLabel:'companyName',companySubtitleLabel:'subtitle',companyAccentLabel:'companyColor',companyContactLabel:'contactEmail',companyFooterLabel:'footer',companyLogoLabel:'companyLogo',companyLogoHint:'logoHint',checkUpdate:'checkUpdates',githubReleaseLink:'openGithub',deleteLogo:'deleteLogo',settingsCancel:'cancel',settingsSaveTitle:'saveCustomization',settingsSaveHint:'saveHint',adminEyebrow:'administration',adminTitle:'settingsAccess',adminHelp:'adminHelp',adminPasswordLabel:'adminPassword',adminCancel:'cancel',adminUnlockTitle:'unlock',adminUnlockHint:'temporarySession',communicationLanguageLabel:'communicationLanguage',communicationsSettingsTitle:'communicationsSettings',appPublicUrlLabel:'appPublicUrl',appPublicUrlHint:'appPublicUrlHint',messagingTitle:'messaging',messagingHint:'messagingHint',matrixAvailable:'available',matrixHomeserverLabel:'matrixHomeserver',matrixTokenLabel:'matrixToken',matrixTokenHint:'matrixTokenHint',matrixRoomLabel:'matrixRoom',matrixNotifyNewLabel:'matrixNotifyNew',matrixNotifyChangedLabel:'matrixNotifyChanged',matrixNotifyDailyLabel:'matrixNotifyDaily',testMatrix:'testMatrix'};for(const [id,key] of Object.entries(ids))setText(id,key);document.querySelectorAll('.disabled-connector small').forEach(e=>e.textContent=tr('comingSoon'));document.querySelectorAll('[data-i18n]').forEach(e=>e.textContent=tr(e.dataset.i18n));document.querySelectorAll('[data-i18n-placeholder]').forEach(e=>e.placeholder=tr(e.dataset.i18nPlaceholder));document.querySelectorAll('[data-fr][data-en]').forEach(e=>e.textContent=language==='en'?e.dataset.en:e.dataset.fr);
 $('search').placeholder=tr('searchPlaceholder');$('resendRecipients').placeholder=language==='en'?'person@domain.com; other@domain.com':'personne@domaine.fr; autre@domaine.fr';$('resendNote').placeholder=tr('notePlaceholder');
 const setOptions=(id,options)=>{const el=$(id),value=el.value;el.innerHTML=options.map(([v,k])=>`<option value="${v}">${tr(k)}</option>`).join('');el.value=value};setOptions('env',[['','all']]);setOptions('status',[['','all']]);setOptions('priority',[['','allF']]);setOptions('timeFilter',[['','all'],['defined','defined'],['missing','toSpecify']]);
 document.querySelectorAll('[data-cal]').forEach(b=>b.textContent=tr(b.dataset.cal));if($('communicationLanguage'))$('communicationLanguage').value=settings.communication_language||language;fill();render();
}
function setTheme(theme){document.documentElement.dataset.theme=theme;localStorage.setItem('mep-theme',theme);$('themeIcon').textContent=theme==='dark'?'☀':'☾';$('themeText').textContent=theme==='dark'?tr('light'):tr('dark')}

function syncLabel(){if(!lastSync)return tr('syncing');const sec=Math.max(0,Math.floor((Date.now()-lastSync)/1000));if(sec<60)return tr('syncedSeconds',{count:sec});if(sec<3600)return tr('syncedMinutes',{count:Math.floor(sec/60)});return tr('syncedAt',{time:lastSync.toLocaleTimeString(locale(),{hour:'2-digit',minute:'2-digit'})})}
async function api(url,options={}){options={...options,headers:{...(options.headers||{})}};if(userToken)options.headers.Authorization=`Bearer ${userToken}`;const r=await fetch(url,options);const d=await r.json().catch(()=>({}));if(r.status===401&&url!='/api/auth/login'){logout(false);throw new Error(d.detail||'Session expired')}if(!r.ok)throw new Error(d.detail||`Erreur HTTP ${r.status}`);return d}
async function load(){try{const [d,n,s]=await Promise.all([api('/api/issues'),api('/api/notifications?limit=500'),api('/api/settings')]);active=d.issues||[];historyIssues=d.history||[];notifications=n.notifications||[];settings=s;language=s.language||language;lastSync=d.last_sync?new Date(d.last_sync):null;$('mode').textContent=d.error?tr('redmineError'):d.mode==='redmine'?tr('connected'):tr('demo');$('dot').style.background=d.error?'#ff5b67':d.mode==='redmine'?'#2fd07f':'#f5c451';$('sync').textContent=syncLabel();applyBranding();fill();render()}catch(e){$('mode').textContent=tr('apiError');$('dot').style.background='#ff5b67'}}
function applyBranding(){const box=$('companyBrand'),logo=$('companyBrandLogo');if(box){if(settings.company_logo_configured){box.classList.remove('hidden');if(logo){logo.src=`/api/settings/company-logo?v=${Date.now()}`;logo.style.display='block';logo.alt=settings.company_name||'Company logo'}}else box.classList.add('hidden')}if(settings.company_accent)document.documentElement.style.setProperty('--company-accent',settings.company_accent);language=settings.language||language;applyLanguage()}
function fill(){[['env','environment'],['status','status'],['priority','priority']].forEach(([id,k])=>{const s=$(id),v=s.value,first=s.options[0].outerHTML;s.innerHTML=first+[...new Set([...active,...historyIssues].map(i=>i[k]).filter(Boolean))].sort().map(x=>`<option>${esc(x)}</option>`).join('');s.value=v})}
function filtered(){const src=view==='history'?historyIssues:active,e=$('env').value,s=$('status').value,p=$('priority').value,t=$('timeFilter').value,q=$('search').value.toLowerCase();return src.filter(i=>(view!=='today'||i.start_date===TODAY)&&(!e||i.environment===e)&&(!s||i.status===s)&&(!p||i.priority===p)&&(!t||(t==='defined'?!!i.start_time:!i.start_time))&&(!q||`${i.id} ${i.subject} ${i.author} ${i.assigned_to} ${i.environment} ${(i.notification?.recipients||[]).join(' ')}`.toLowerCase().includes(q))).sort((a,b)=>`${a.start_date}${a.start_time||'99:99'}`.localeCompare(`${b.start_date}${b.start_time||'99:99'}`))}
function mailState(i){const n=i.notification||{};if(n.sent)return`<span class="mail-ok">✓ ${tr('sentCount',{count:n.count})}</span><small>${esc((n.recipients||[]).join('; '))}<br>${n.last?.sent_at?new Date(n.last.sent_at).toLocaleString(locale()):''}</small>`;if(n.errors)return`<span class="mail-ko">⚠ ${tr('errorCount',{count:n.errors})}</span>`;return`<span class="mail-none">${tr('notSent')}</span>`}
function render(){const titles={dashboard:[tr('dashboard'),tr('dashboardSubtitle')],today:[tr('today'),tr('todaySubtitle',{date:fmt(TODAY)})],history:[tr('history'),tr('historySubtitle')],communications:[tr('communications'),tr('communicationsSubtitle')],settings:[tr('settings'),language==='en'?'Application administration and integrations':'Administration de l’application et des intégrations'],profile:[language==='en'?'Profile':'Profil',language==='en'?'Personal preferences':'Préférences personnelles'],reports:[language==='en'?'Reports':'Rapports',language==='en'?'Activity and planning quality':'Activité et qualité de planification']}[view]||[tr('dashboard'),tr('dashboardSubtitle')];$('pageTitle').textContent=titles[0];$('pageSubtitle').textContent=titles[1];const inSettings=view==='settings',inProfile=view==='profile',inReports=view==='reports',special=inSettings||inProfile||inReports;if($('settingsView'))$('settingsView').classList.toggle('hidden',!inSettings);if($('profileView'))$('profileView').classList.toggle('hidden',!inProfile);if($('reportsView'))$('reportsView').classList.toggle('hidden',!inReports);$('stats').style.display=special?'none':'grid';$('listPanel').style.display=special?'none':'block';$('calendarPanel').style.display=special||['history','communications'].includes(view)?'none':'block';$('filters').style.display=special||view==='communications'?'none':'grid';document.querySelector('.head-actions').style.display=special?'none':'flex';if(special)return;$('stats').innerHTML=[[tr('todayStat'),active.filter(i=>i.start_date===TODAY).length],[tr('missingTime'),active.filter(i=>!i.start_time).length],[tr('urgentImmediate'),active.filter(urgent).length],[tr('upcomingTotal'),active.filter(i=>(i.start_date||'')>=TODAY).length]].map(x=>`<div class="stat"><span>${x[0]}</span><strong>${x[1]}</strong></div>`).join('');view==='communications'?renderNotifications():renderIssues()}
function renderIssues(){if(view==='today'){calMode='day';cursor=new Date(TODAY+'T12:00:00')}$('listTitle').textContent=view==='history'?tr('completed'):view==='today'?tr('todayPlanned'):tr('planned');$('listSubtitle').textContent=tr('missingTimeHelp');$('thead').innerHTML=`<tr><th>${tr('ticket')}</th><th>${tr('status')}</th><th>${tr('priority')}</th><th>${tr('assignedTo')}</th><th>${tr('schedule')}</th><th>${tr('environment')}</th><th>${tr('actions')}</th></tr>`;$('rows').innerHTML=filtered().map(i=>`<tr class="${urgent(i)?'urgent-row':''} ${immediate(i)?'immediate-row':''}"><td><span class="ticket">#${i.id}</span><br>${esc(i.subject)}</td><td><span class="badge">${esc(i.status)}</span></td><td><span class="badge priority-${i.priority_level}">${esc(i.priority)}</span></td><td>${esc(i.assigned_to)}</td><td>${fmt(i.start_date)}<br><span class="${i.start_time?'':'time-missing'}">${esc(planningText(i))}</span></td><td><span class="badge env ${envClass(i.environment)}">${esc(i.environment)}</span></td><td><div class="row-actions"><button class="small details" onclick="openIssue(${i.id})">${tr('details')}</button><a class="small" href="${esc(i.url)}" target="_blank">${tr('openRedmine')}</a></div></td></tr>`).join('')||`<tr><td colspan="7" class="empty">${tr('noneRelease')}</td></tr>`;renderCalendar()}
function renderNotifications(){const q=$('search').value.toLowerCase();$('listTitle').textContent=tr('communicationHistory');$('listSubtitle').textContent=tr('manualVsAuto');$('thead').innerHTML=`<tr><th>${tr('date')}</th><th>${tr('ticket')}</th><th>${tr('type')}</th><th>${tr('subject')}</th><th>${tr('recipients')}</th><th>${tr('state')}</th><th>PDF</th></tr>`;$('rows').innerHTML=notifications.filter(n=>!q||`${n.issue_id} ${n.subject} ${n.recipients} ${n.status}`.toLowerCase().includes(q)).map(n=>`<tr><td>${new Date(n.sent_at).toLocaleString(locale())}</td><td>${n.issue_id?'#'+n.issue_id:'—'}</td><td>${n.manual?tr('manual'):esc(n.notification_type)}</td><td>${esc(n.subject)}</td><td>${esc(n.recipients)}</td><td><span class="${n.status==='sent'?'mail-ok':'mail-ko'}">${n.status==='sent'?tr('sent'):tr('error')}</span>${n.error?`<small>${esc(n.error)}</small>`:''}</td><td>${n.pdf_attached?'✓':'—'}</td></tr>`).join('')||`<tr><td colspan="7" class="empty">${tr('noneCommunication')}</td></tr>`}
function weekStart(d){const x=new Date(d),n=(x.getDay()+6)%7;x.setDate(x.getDate()-n);x.setHours(12,0,0,0);return x}
function renderCalendar(){if(view==='history'||view==='communications')return;document.querySelectorAll('[data-cal]').forEach(b=>b.classList.toggle('active',b.dataset.cal===calMode));calMode==='day'?dayCal():calMode==='month'?monthCal():weekCal()}
function eventHtml(i,c='cal-event',style=''){return`<div class="${c} ${envClass(i.environment)} ${urgent(i)?'urgent':''}" ${style?`style="${style}"`:''} onclick="openIssue(${i.id})">${i.start_time?esc(planningText(i))+' · ':''}#${i.id}<br>${esc(i.subject)}</div>`}
function unscheduled(items){return items.length?`<div class="unscheduled"><strong>${tr('unscheduled')}</strong><div>${items.map(i=>eventHtml(i,'unscheduled-event')).join('')}</div></div>`:''}
function eventDuration(i){const start=mins(i.start_time);if(start===null)return 30;let end=mins(i.end_time);if(end!==null&&end<=start)end+=1440;if(end===null&&i.estimated_hours)end=start+Number(i.estimated_hours)*60;return Math.max(30,(end??start+30)-start)}
function weekCal(){const st=weekStart(cursor),days=[...Array(7)].map((_,i)=>{const d=new Date(st);d.setDate(d.getDate()+i);return d}),range=days.map(iso),missing=active.filter(i=>range.includes(i.start_date)&&!i.start_time);let h=unscheduled(missing)+`<div class="week-grid"><div class="week-head"></div>${days.map(d=>`<div class="week-head ${iso(d)===TODAY?'today':''}">${new Intl.DateTimeFormat(locale(),{weekday:'short',day:'2-digit',month:'2-digit'}).format(d)}</div>`).join('')}<div class="week-times">${[...Array(24)].map((_,hour)=>`<div class="time-label">${String(hour).padStart(2,'0')}:00</div>`).join('')}</div>`;for(const d of days){const ds=iso(d);let col=[...Array(24)].map(()=>'<div class="week-slot"></div>').join('');for(const i of active.filter(i=>i.start_date===ds&&i.start_time)){const top=mins(i.start_time),height=eventDuration(i);col+=eventHtml(i,'cal-event',`top:${top}px;height:${height}px`)}h+=`<div class="week-day-area">${col}</div>`}$('calendar').innerHTML=h+'</div>';$('calendarTitle').textContent=tr('weekOf',{date:fmt(iso(st))})}
function dayCal(){const ds=iso(cursor),items=active.filter(i=>i.start_date===ds),missing=items.filter(i=>!i.start_time);let l='',r='';for(let h=0;h<24;h++){l+=`<div class="day-time">${String(h).padStart(2,'0')}:00</div>`;r+='<div class="day-slot"></div>'}for(const i of items.filter(i=>i.start_time)){const top=mins(i.start_time),height=eventDuration(i);r+=eventHtml(i,'day-event',`top:${top}px;height:${height}px`)}$('calendar').innerHTML=unscheduled(missing)+`<div class="day-calendar"><div>${l}</div><div class="day-area">${r}</div></div>`;$('calendarTitle').textContent=tr('dayOf',{date:fmt(ds)})}
function monthCal(){const y=cursor.getFullYear(),m=cursor.getMonth(),st=weekStart(new Date(y,m,1,12));let h='<div class="month-grid">'+(language==='en'?['Mon','Tue','Wed','Thu','Fri','Sat','Sun']:['Lun','Mar','Mer','Jeu','Ven','Sam','Dim']).map(n=>`<div class="month-head">${n}</div>`).join('');for(let n=0;n<42;n++){const d=new Date(st);d.setDate(d.getDate()+n);const ds=iso(d);h+=`<div class="month-cell ${d.getMonth()!==m?'other':''} ${ds===TODAY?'today':''}"><div>${d.getDate()}</div>${active.filter(i=>i.start_date===ds).map(i=>eventHtml(i,'month-event')).join('')}</div>`}$('calendar').innerHTML=h+'</div>';$('calendarTitle').textContent=new Intl.DateTimeFormat(locale(),{month:'long',year:'numeric'}).format(cursor)}
window.openIssue=id=>{const i=[...active,...historyIssues].find(x=>x.id===id);if(!i)return;currentIssue=i;$('d-id').textContent=`Ticket #${i.id}`;$('d-title').textContent=i.subject;$('d-desc').textContent=i.description;$('d-link').href=i.url;$('pdfLink').href=`/api/issues/${i.id}/report.pdf`;$('d-meta').innerHTML=[[tr('status'),i.status],[tr('priority'),i.priority],[tr('environment'),i.environment],[tr('createdBy'),i.author],[tr('assignedTo'),i.assigned_to],[tr('estimatedTime'),`${i.estimated_hours||'—'} h`],[tr('start'),`${fmt(i.start_date)} · ${planningText(i)}`],[tr('due'),`${fmt(i.due_date)}${i.end_time?' · '+i.end_time:''}`]].map(x=>`<div><span>${x[0]}</span><strong>${esc(x[1])}</strong></div>`).join('');$('d-mail').innerHTML=mailState(i);$('sendResult').textContent='';$('resendRecipients').value='';$('resendNote').value='';$('issueDialog').showModal()}
async function resend(custom){if(!currentIssue)return;const recipients=custom?$('resendRecipients').value.split(';').map(x=>x.trim()).filter(Boolean):null;if(custom&&!recipients.length){$('sendResult').textContent=tr('enterRecipient');return}$('sendResult').textContent=tr('sending');try{await api(`/api/issues/${currentIssue.id}/resend`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({recipients,include_pdf:$('includePdf').checked,include_calendar:true,note:$('resendNote').value})});$('sendResult').textContent=tr('sendSuccess');await load();currentIssue=[...active,...historyIssues].find(x=>x.id===currentIssue.id);$('d-mail').innerHTML=mailState(currentIssue)}catch(e){$('sendResult').textContent=tr('failure',{message:e.message})}}
const closeDialog=()=>{if($('issueDialog').open)$('issueDialog').close()};

function activateSettingsTab(name){if(name==='logs')loadLogs();if(name==='health')loadHealth();if(name==='backups')loadBackups();document.querySelectorAll('.settings-tab').forEach(b=>b.classList.toggle('active',b.dataset.settingsTab===name));document.querySelectorAll('.settings-page').forEach(p=>p.classList.toggle('active',p.dataset.settingsPage===name));}
document.querySelectorAll('.settings-tab').forEach(b=>b.addEventListener('click',()=>activateSettingsTab(b.dataset.settingsTab)));

async function openSettings(){try{settings=await api('/api/settings');$('companyName').value=settings.company_name||'';$('companySubtitle').value=settings.company_subtitle||'';$('companyAccent').value=settings.company_accent||'#5B7CFA';$('companyContact').value=settings.company_contact_email||'';$('companyFooter').value=settings.company_footer||'';if($('communicationLanguage'))$('communicationLanguage').value=settings.communication_language||settings.language||'fr';$('appPublicUrl').value=settings.app_public_url||'';$('matrixEnabled').checked=!!settings.matrix_enabled;$('matrixHomeserver').value=settings.matrix_homeserver||'';$('matrixToken').value='';$('matrixToken').placeholder=settings.matrix_token_configured?'•••••••••••• (configured)':'••••••••••••';$('matrixRoomId').value=settings.matrix_room_id||'';$('matrixNotifyNew').checked=settings.matrix_notify_new!==false;$('matrixNotifyChanged').checked=settings.matrix_notify_changed!==false;$('matrixNotifyDaily').checked=!!settings.matrix_notify_daily;$('matrixTestResult').textContent='';updateSettingsPreview();$('settingsResult').textContent='';await loadAdminConfiguration();activateSettingsTab('communications');view='settings';document.querySelectorAll('.nav').forEach(x=>x.classList.remove('active'));$('settingsNav').classList.add('active');render();checkUpdate()}catch(e){alert(e.message)}}
function updateSettingsPreview(){const n=$('companyName').value||'My Company',sub=$('companySubtitle').value||'IT Operations';$('settingsNamePreview').textContent=n;$('settingsSubtitlePreview').textContent=sub;$('settingsNamePreview').style.color=$('companyAccent').value;if(settings.company_logo_configured&&!$('companyLogo').files.length){$('settingsLogoPreview').src=`/api/settings/company-logo?v=${Date.now()}`;$('settingsLogoPreview').style.display='block'}else if(!$('companyLogo').files.length)$('settingsLogoPreview').style.display='none'}
async function saveSettings(e){e.preventDefault();$('settingsResult').textContent=tr('saving');try{await api('/api/settings',{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({company_name:$('companyName').value,company_subtitle:$('companySubtitle').value,company_accent:$('companyAccent').value,company_contact_email:$('companyContact').value,company_footer:$('companyFooter').value,language,communication_language:$('communicationLanguage').value,app_public_url:$('appPublicUrl').value,matrix_enabled:$('matrixEnabled').checked,matrix_homeserver:$('matrixHomeserver').value,matrix_access_token:$('matrixToken').value,matrix_room_id:$('matrixRoomId').value,matrix_notify_new:$('matrixNotifyNew').checked,matrix_notify_changed:$('matrixNotifyChanged').checked,matrix_notify_daily:$('matrixNotifyDaily').checked})});await saveInfrastructure();const f=$('companyLogo').files[0];if(f){const form=new FormData();form.append('file',f);await api('/api/settings/company-logo',{method:'POST',body:form})}await uploadOptionalBranding('companyLogoDark','logo-dark');await uploadOptionalBranding('companyFavicon','favicon');await uploadOptionalBranding('loginBackground','login-background');$('settingsResult').textContent=tr('saved');await load();setTimeout(()=>{$('settingsResult').textContent=''},1800)}catch(e){$('settingsResult').textContent=tr('failure',{message:e.message})}}


