async function saveInfrastructure(){await api('/api/admin/configuration',{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(configPayload())})}
async function testAdminEndpoint(url,resultId){const e=$(resultId);e.textContent=language==='en'?'Testing…':'Test en cours…';try{await saveInfrastructure();const d=await api(url,{method:'POST'});if(url.includes('/redmine/')){e.textContent='✓ '+(language==='en'?'Connected as ':'Connecté en tant que ')+(d.user||'—')+' · '+(d.server||'');$('mode').textContent=tr('connected');$('dot').style.background='#2fd07f';setTimeout(()=>load(),1200)}else e.textContent='✓ '+(d.user||d.issuer||d.vendor||d.message_id||'OK')}catch(x){e.textContent='✕ '+x.message;if(url.includes('/redmine/')){$('mode').textContent=tr('redmineError');$('dot').style.background='#ff5b67'}}}
async function loadUsers(){if(!$('usersTable'))return;try{const d=await api('/api/admin/users');window.adminUsers=d.users;renderUsers()}catch(e){$('usersTable').textContent=e.message}}
function renderUsers(){const q=($('userSearch')?.value||'').toLowerCase();const rows=(window.adminUsers||[]).filter(u=>!q||`${u.username} ${u.display_name} ${u.email}`.toLowerCase().includes(q));$('usersTable').innerHTML=rows.map(u=>`<div class="user-row"><div><b>${esc(u.display_name||u.username)}</b><small>${esc(u.username)}</small></div><div>${esc(u.email||'—')}</div><div>${esc(u.source)}</div><div><span class="user-role">${u.role==='admin'?tr('roleAdmin'):tr('roleUser')}</span></div><div>${u.last_login?new Date(u.last_login).toLocaleString(locale()):'—'}</div><button type="button" class="secondary edit-user" data-id="${u.id}">${tr('edit')}</button></div>`).join('')||`<p>${tr('noUsers')}</p>`;document.querySelectorAll('.edit-user').forEach(b=>b.onclick=()=>editUser(+b.dataset.id))}
