async function uploadOptionalBranding(id, asset){const el=$(id);if(!el||!el.files[0])return;const form=new FormData();form.append('file',el.files[0]);await api('/api/settings/branding/'+asset,{method:'POST',body:form})}
function formatUptime(seconds){if(seconds==null)return '—';const d=Math.floor(seconds/86400),h=Math.floor(seconds%86400/3600),m=Math.floor(seconds%3600/60);return `${d}j ${h}h ${m}m`}
async function loadHealth(){
 const summary=$('healthSummary'),services=$('healthServices'),resources=$('healthResources'),alerts=$('healthAlerts'),loading=$('healthLoading');
 if(!summary)return;
 if(loading){loading.classList.remove('hidden');loading.textContent=language==='en'?'Loading health information…':'Chargement des informations de santé…'}
 summary.innerHTML='';services.innerHTML='';resources.innerHTML='';alerts.innerHTML='';
 try{
  const d=await api('/api/system/health-details');
  if(loading)loading.classList.add('hidden');
  const cls=d.score>=80?'good':d.score>=50?'warning':'bad';
  summary.innerHTML=`<article class="health-score ${cls}"><div><span>${language==='en'?'OVERALL STATUS':'ÉTAT GÉNÉRAL'}</span><strong>${esc(String(d.score))}/100</strong><small>MEP Planner ${esc(d.version)}</small></div><div class="score-ring" style="--score:${Number(d.score)}">${esc(String(d.score))}</div></article>`;
  const serviceLabels={api:'API',database:language==='en'?'Database':'Base de données',scheduler:language==='en'?'Scheduler':'Planificateur',smtp:'SMTP',ldap:'LDAP',redmine:'Redmine'};
  const statusLabels={ok:language==='en'?'Operational':'Opérationnel',configured:language==='en'?'Configured':'Configuré',disabled:language==='en'?'Disabled':'Désactivé',warning:language==='en'?'Warning':'Avertissement',error:language==='en'?'Error':'Erreur'};
  services.innerHTML=Object.entries(d.checks||{}).map(([key,c])=>`<article class="service-card ${esc(c.status)}"><span class="service-dot"></span><div><strong>${esc(serviceLabels[key]||c.label||key)}</strong><small>${esc(c.detail||statusLabels[c.status]||c.status)}</small></div></article>`).join('');
  const r=d.resources||{};
  const none=language==='en'?'None':'Aucune',never=language==='en'?'Never':'Jamais';
  const rows=[[language==='en'?'Disk':'Disque',`${r.disk_percent??0}% · ${r.disk_used||'-'} / ${r.disk_total||'-'}`],[language==='en'?'Database':'Base de données',r.database_size||'-'],[language==='en'?'Backups':'Sauvegardes',`${r.backup_count??0} · ${r.backups_size||'-'}`],['Uptime',formatUptime(r.uptime_seconds)],[language==='en'?'Last backup':'Dernière sauvegarde',d.last_backup?new Date(d.last_backup.created_at).toLocaleString():none],[language==='en'?'Last synchronization':'Dernière synchronisation',d.last_sync?new Date(d.last_sync).toLocaleString():never]];
  resources.innerHTML=rows.map(([k,v])=>`<div class="health-item"><span>${esc(k)}</span><strong>${esc(String(v))}</strong></div>`).join('');
  const alertMap={'Aucune sauvegarde disponible':language==='en'?'No backup is available':'Aucune sauvegarde disponible','Espace disque critique':language==='en'?'Critical disk usage':'Espace disque critique','Dernière synchronisation Redmine en erreur':language==='en'?'The latest Redmine synchronization failed':'Dernière synchronisation Redmine en erreur','Base de données inaccessible':language==='en'?'Database is unavailable':'Base de données inaccessible'};
  alerts.innerHTML=(d.alerts||[]).length?(d.alerts||[]).map(a=>`<div class="health-alert">⚠ ${esc(alertMap[a]||a)}</div>`).join(''):`<div class="health-ok">✓ ${language==='en'?'No active alerts':'Aucune alerte active'}</div>`;
 }catch(e){
  if(loading)loading.classList.add('hidden');
  const msg=language==='en'?'Unable to load Health Center data.':'Impossible de charger les données du Centre de santé.';
  summary.innerHTML=`<div class="error"><strong>${esc(msg)}</strong><br><small>${esc(e.message)}</small></div>`;
  services.innerHTML=`<article class="service-card error"><span class="service-dot"></span><div><strong>API</strong><small>${esc(e.message)}</small></div></article>`;
  resources.innerHTML=`<div class="health-item"><span>${language==='en'?'Status':'État'}</span><strong>${language==='en'?'Unavailable':'Indisponible'}</strong></div>`;
  alerts.innerHTML=`<div class="health-alert">⚠ ${esc(msg)}</div>`;
 }
}
if($('refreshHealth'))$('refreshHealth').onclick=loadHealth;
async function loadBackups(){if(!$('backupRows'))return;try{const d=await api('/api/backups');const empty=language==='en'?'No backups found.':'Aucune sauvegarde.';$('backupRows').innerHTML=d.backups.length?d.backups.map(b=>`<tr><td>${esc(new Date(b.created_at).toLocaleString())}</td><td><code>${esc(b.name)}</code></td><td>${esc(b.size_human)}</td><td class="backup-actions"><button class="secondary" data-download="${esc(b.name)}">${language==='en'?'Download':'Télécharger'}</button><button class="secondary" data-restore="${esc(b.name)}">${language==='en'?'Restore':'Restaurer'}</button><button class="secondary danger" data-delete="${esc(b.name)}">${language==='en'?'Delete':'Supprimer'}</button></td></tr>`).join(''):`<tr><td colspan="4">${empty}</td></tr>`;document.querySelectorAll('[data-download]').forEach(x=>x.onclick=()=>downloadBackup(x.dataset.download));document.querySelectorAll('[data-delete]').forEach(x=>x.onclick=()=>deleteBackup(x.dataset.delete));document.querySelectorAll('[data-restore]').forEach(x=>x.onclick=()=>restoreBackup(x.dataset.restore))}catch(e){$('backupRows').innerHTML=`<tr><td colspan="4" class="error">${esc(e.message)}</td></tr>`}}
async function downloadBackup(name){const headers={};if(userToken)headers.Authorization='Bearer '+userToken;else if(adminToken)headers.Authorization='Bearer '+adminToken;const r=await fetch('/api/backups/'+encodeURIComponent(name)+'/download',{headers});if(!r.ok)throw new Error(await r.text());const blob=await r.blob(),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=name;a.click();URL.revokeObjectURL(url)}
async function createBackup(){try{$('backupResult').textContent=language==='en'?'Creating…':'Création…';const d=await api('/api/backups',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name:$('backupName').value,include_logs:$('backupIncludeLogs').checked})});$('backupResult').textContent='✓ '+d.backup.name;await loadBackups();await loadHealth()}catch(e){$('backupResult').textContent='✕ '+e.message}}
async function importBackup(){const file=$('backupImportFile').files[0];if(!file){$('backupImportResult').textContent=language==='en'?'Select a ZIP file.':'Sélectionnez un ZIP.';return}try{$('backupImportResult').textContent=language==='en'?'Importing…':'Import…';const form=new FormData();form.append('file',file);const d=await api('/api/backups/import',{method:'POST',body:form});$('backupImportResult').textContent='✓ '+d.name;await loadBackups()}catch(e){$('backupImportResult').textContent='✕ '+e.message}}
async function deleteBackup(name){if(!confirm((language==='en'?'Permanently delete ':'Supprimer définitivement ')+name+' ?'))return;await api('/api/backups/'+encodeURIComponent(name),{method:'DELETE'});await loadBackups();await loadHealth()}
async function restoreBackup(name){if(!confirm(language==='en'?`Restore ${name}? A safety backup will be created before restoration.`:`Restaurer ${name} ? Une sauvegarde de sécurité sera créée avant la restauration.`))return;try{$('backupResult').textContent=language==='en'?'Restoring…':'Restauration…';const d=await api('/api/backups/restore',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({backup_name:name,restore_database:true,restore_branding:true,restore_settings:true,restore_logs:false})});alert(language==='en'?`Restore completed. Safety backup: ${d.safety_backup}\nRestart the containers to apply all restored items.`:`Restauration terminée. Sauvegarde de sécurité : ${d.safety_backup}\nRedémarrez les conteneurs pour appliquer tous les éléments.`);await loadBackups();await loadHealth()}catch(e){alert((language==='en'?'Failed: ':'Échec : ')+e.message)}}
if($('createBackup'))$('createBackup').onclick=createBackup;if($('importBackup'))$('importBackup').onclick=importBackup;if($('refreshBackups'))$('refreshBackups').onclick=loadBackups;
if($('testSmtp'))$('testSmtp').onclick=async()=>{try{await saveInfrastructure();$('smtpTestResult').textContent=language==='en'?'Test in progress…':'Test en cours…';const d=await api('/api/admin/smtp/test',{method:'POST'});$('smtpTestResult').textContent=(language==='en'?'✓ Email sent ':'✓ E-mail envoyé ')+(d.message_id||'')}catch(e){$('smtpTestResult').textContent='✕ '+e.message}};
